args.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?season ?year ?numRaces
WHERE {
  ?season wdt:P1346 wd:Q9673;
          wdt:P31 wd:Q17547279;
          wdt:P580 ?start;
          wdt:P1113 ?numRaces.
  BIND(xsd:integer(YEAR(?start)) AS ?year)
  FILTER (?year > 2015)
}
ORDER BY ASC(?numRaces)
LIMIT 3
